700 |         async function decryptCtx(buffer) {
701 |             const keyBytes = new TextEncoder().encode("C0rtexS3cr3tK3y!");
702 |             const iv = buffer.slice(0, 12);
703 |             const ciphertext = buffer.slice(12);
704 |             
705 |             const cryptoKey = await crypto.subtle.importKey("raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]);
706 |             const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv }, cryptoKey, ciphertext);
707 |             
708 |             const decompressedBuffer = await decompressGzip(decrypted);
709 |             return JSON.parse(new TextDecoder().decode(decompressedBuffer));
710 |         }
