712 |         async function decompressGzip(buffer) {
713 |             const ds = new DecompressionStream("gzip");
714 |             const writer = ds.writable.getWriter();
715 |             writer.write(buffer);
716 |             writer.close();
717 |             const response = new Response(ds.readable);
718 |             return await response.arrayBuffer();
719 |         }
